+function looksLikeLocalPluginInstallSpec(raw: string): boolean {
+  return (
+    raw.startsWith(".") ||
+    raw.startsWith("~") ||
+    raw.startsWith("/") ||
+    raw.endsWith(".ts") ||
+    raw.endsWith(".js") ||
+    raw.endsWith(".mjs") ||
+    raw.endsWith(".cjs") ||
+    raw.endsWith(".tgz") ||
+    raw.endsWith(".tar.gz") ||
+    raw.endsWith(".tar") ||
+    raw.endsWith(".zip")
+  );
+}
